{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOHzwe84k5AhezEvcnAxrOy"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"roB-sgcnhNcV"},"outputs":[],"source":["#Defining find and replace function\n","def find_and_replace(lst,find_val,replace_val):\n","\n","    \"\"\"\n","    Task 1\n","    - Create a function that searches for all occurrences of a value (find_val) in a given list (lst) and replaces them with another value (replace_val).\n","    - lst must be a list.\n","    - Return the modified list.\n","    \"\"\"\n","    for i in range(len(lst)): #loop through the list\n","        if lst[i] == find_val: # search for the value to find\n","            lst[i] = replace_val #replace it with the replacement value\n","    return lst #return the modified list\n","'''\n","# Task 2\n","# Invoke the function \"find_and_replace\" using the following scenarios:\n","# - [1, 2, 3, 4, 2, 2], 2, 5\n","# - [\"apple\", \"banana\", \"apple\"], \"apple\", \"orange\"\n","'''\n","\n","#case1\n","print(find_and_replace([1, 2, 3, 4, 2, 2], 2, 5))\n","\n","#case2\n","print(find_and_replace( [\"apple\", \"banana\", \"apple\"], \"apple\", \"orange\"))\n"]}]}